import heapq

def solve(m: int, n: int, waitCost: list[list[int]]) -> int:
    heap = []
    heapq.heappush(heap, (1, 0, 0, 1))
    dist = {}
    dist[(0, 0, 1)] = 1
    directions = [(0, 1), (1, 0)]

    while heap:
        cost, i, j, t = heapq.heappop(heap)
        if i == m - 1 and j == n - 1:
            return cost
        if (i, j, t) in dist and dist[(i, j, t)] < cost:
            continue
        if t % 2 == 1:
            for di, dj in directions:
                ni, nj = i + di, j + dj
                if 0 <= ni < m and 0 <= nj < n:
                    new_time = t + 1
                    new_cost = cost + (ni + 1) * (nj + 1)
                    key = (ni, nj, new_time)
                    if key not in dist or new_cost < dist[key]:
                        dist[key] = new_cost
                        heapq.heappush(heap, (new_cost, ni, nj, new_time))
        else:
            new_time = t + 1
            new_cost = cost + waitCost[i][j]
            key = (i, j, new_time)
            if key not in dist or new_cost < dist[key]:
                dist[key] = new_cost
                heapq.heappush(heap, (new_cost, i, j, new_time))
    return -1
