import sys

def solve(m: int, n: int, waitCost: list[list[int]]) -> int:
    inf = float('inf')
    max_time = m + n
    dp = [[[inf] * (max_time + 2) for _ in range(n)] for _ in range(m)]
    dp[0][0][1] = (0 + 1) * (0 + 1)

    for t in range(1, max_time + 1):
        for i in range(m):
            for j in range(n):
                current_cost = dp[i][j][t]
                if current_cost == inf:
                    continue
                if t % 2 == 1:
                    if j + 1 < n:
                        new_i, new_j = i, j + 1
                        new_t = t + 1
                        entry_cost = (new_i + 1) * (new_j + 1)
                        new_cost = current_cost + entry_cost
                        if new_cost < dp[new_i][new_j][new_t]:
                            dp[new_i][new_j][new_t] = new_cost
                    if i + 1 < m:
                        new_i, new_j = i + 1, j
                        new_t = t + 1
                        entry_cost = (new_i + 1) * (new_j + 1)
                        new_cost = current_cost + entry_cost
                        if new_cost < dp[new_i][new_j][new_t]:
                            dp[new_i][new_j][new_t] = new_cost
                else:
                    new_t = t + 1
                    wait_cost = waitCost[i][j]
